/**
 * Bottom snow accumulation – CodePen-style. Grows independently with simulated
 * landings so the pile feels like many particles without the snow renderer.
 * Snow only sticks when supported (pixel below or ground), giving an irregular shape.
 * Also mounts the "santa running" effect (#path > #santa) above the pile.
 * Paste your Santa sprite base64 string into SANTA_SPRITE_BASE64 below to show the running Santa.
 * Santa animation assumes a 12-frame horizontal sprite, 85px per frame (total width 1020px).
 * If your sprite has a different frame count, set steps() to that count and end position to -(count * 85).
 */

const PILE_HEIGHT = 220;

/** Paste your base64-encoded Santa sprite image here (raw base64, no "data:image/png;base64," prefix). Leave empty to hide Santa. */
const SANTA_SPRITE_BASE64 = "data:image/png;base64,";

const SANTA_PATH_STYLES = `
#umb-christmas-santa-path {
  position: fixed;
  bottom: 0;
  left: auto;
  margin-top: -85px;
  animation: umb-santa-path-animation 10s infinite;
  z-index: 100;
  pointer-events: none;
}
#umb-christmas-santa-path #santa {
  width: 85px;
  height: 85px;
  border: 1px solid transparent;
  background: var(--umb-santa-sprite) no-repeat left top;
  background-size: auto 85px;
  animation: umb-santa-animation 0.8s steps(12) infinite;
}
@keyframes umb-santa-animation {
  0% { background-position: 0 0; }
  100% { background-position: -1020px 0; }
}
@keyframes umb-santa-path-animation {
  0% { left: -5%; }
  100% { left: 120%; }
}
`;
const SNOW_R = 255;
const SNOW_G = 255;
const SNOW_B = 255;
const BOTTOM_ROW = PILE_HEIGHT - 1;
/** Simulated landings per frame (lower = better performance). */
const SIMULATED_LANDINGS_PER_FRAME = 6;
/** Throttle accumulation draw to ~20 FPS to reduce CPU. */
const ACCUMULATION_INTERVAL_MS = 50;

export class SnowAccumulation {
    #canvas: HTMLCanvasElement | null = null;
    #ctx: CanvasRenderingContext2D | null = null;
    #animId: number | null = null;
    #w = 0;
    #buffer: Uint8Array | null = null;
    #topOfSnow: Int32Array | null = null;
    #imageData: ImageData | null = null;
    #santaPath: HTMLDivElement | null = null;
    #santaStyles: HTMLStyleElement | null = null;
    #lastDrawTime = 0;

    /** Returns true if snow can be placed at (xi, row): on the ground or supported by snow below (and diagonals). */
    #isSupported(xi: number, row: number): boolean {
        if (row >= BOTTOM_ROW) return true;
        const buf = this.#buffer!;
        const w = this.#w;
        const below = xi + (row + 1) * w;
        const belowL = xi > 0 ? xi - 1 + (row + 1) * w : below;
        const belowR = xi < w - 1 ? xi + 1 + (row + 1) * w : below;
        return buf[below] === 1 && buf[belowL] === 1 && buf[belowR] === 1;
    }

    /** Try to place one pixel at column xi; returns true if placed. */
    #tryLand(xi: number): boolean {
        if (!this.#buffer || !this.#topOfSnow || this.#w <= 0) return false;
        const cx = Math.max(0, Math.min(this.#w - 1, xi));
        const row = this.#topOfSnow[cx];
        if (row < 0) return false;
        if (!this.#isSupported(cx, row)) return false;
        this.#buffer[cx + row * this.#w] = 1;
        this.#topOfSnow[cx] = row - 1;
        return true;
    }

    /** Simulate several random landings per frame so the pile grows without the snow renderer. */
    #simulateLandings(): void {
        const w = this.#w;
        if (w <= 0) return;
        for (let n = 0; n < SIMULATED_LANDINGS_PER_FRAME; n++) {
            const x = Math.floor(Math.random() * w);
            this.#tryLand(x);
        }
    }

    start(container?: HTMLElement): void {
        const parent = container ?? document.body;
        this.#canvas = document.createElement("canvas");
        this.#canvas.id = "umb-christmas-snow-accumulation";
        Object.assign(this.#canvas.style, {
            position: "fixed",
            bottom: "0",
            left: "0",
            width: "100vw",
            height: PILE_HEIGHT + "px",
            pointerEvents: "none",
            zIndex: "0",
            mixBlendMode: "lighten",
        });
        parent.appendChild(this.#canvas);

        // Santa running along the bottom (sprite: set --umb-santa-sprite on document or parent)
        this.#santaPath = document.createElement("div");
        this.#santaPath.id = "umb-christmas-santa-path";
        const santa = document.createElement("div");
        santa.id = "santa";
        this.#santaPath.appendChild(santa);
        parent.appendChild(this.#santaPath);

        this.#santaStyles = document.createElement("style");
        this.#santaStyles.id = "umb-christmas-santa-path-styles";
        let santaVar = "";
        if (SANTA_SPRITE_BASE64.length > 0) {
            const spriteUrl = SANTA_SPRITE_BASE64.startsWith("data:")
                ? SANTA_SPRITE_BASE64
                : `data:image/png;base64,${SANTA_SPRITE_BASE64}`;
            santaVar = `:root { --umb-santa-sprite: url('${spriteUrl}'); }\n`;
        }
        this.#santaStyles.textContent = santaVar + SANTA_PATH_STYLES;
        document.head.appendChild(this.#santaStyles);

        this.#ctx = this.#canvas.getContext("2d", { willReadFrequently: false, alpha: true });
        if (!this.#ctx) {
            this.#canvas.remove();
            this.#canvas = null;
            return;
        }

        this.#resize();
        window.addEventListener("resize", this.#onResize);
        this.#animId = requestAnimationFrame(this.#loop);
    }

    stop(): void {
        if (this.#animId !== null) cancelAnimationFrame(this.#animId);
        window.removeEventListener("resize", this.#onResize);
        this.#santaPath?.remove();
        this.#santaPath = null;
        this.#santaStyles?.remove();
        this.#santaStyles = null;
        this.#canvas?.remove();
        this.#canvas = null;
        this.#ctx = null;
        this.#buffer = null;
        this.#topOfSnow = null;
        this.#imageData = null;
    }

    #onResize = () => this.#resize();

    #resize(): void {
        if (!this.#canvas || !this.#ctx) return;
        const w = Math.max(1, innerWidth);
        this.#w = w;
        this.#canvas.width = w;
        this.#canvas.height = PILE_HEIGHT;
        this.#buffer = new Uint8Array(w * PILE_HEIGHT);
        this.#topOfSnow = new Int32Array(w);
        for (let i = 0; i < w; i++) this.#topOfSnow[i] = PILE_HEIGHT - 1;
        // Ground row so snow can stack immediately (fewer flakes than CodePen).
        for (let xi = 0; xi < w; xi++) this.#buffer[xi + BOTTOM_ROW * w] = 1;
        for (let i = 0; i < w; i++) this.#topOfSnow[i] = BOTTOM_ROW - 1;
        this.#imageData = this.#ctx.getImageData(0, 0, w, PILE_HEIGHT);
    }

    #loop = (now?: number): void => {
        this.#animId = requestAnimationFrame((t) => this.#loop(t));
        const t = now ?? performance.now();
        if (t - this.#lastDrawTime < ACCUMULATION_INTERVAL_MS) return;
        this.#lastDrawTime = t;
        this.#simulateLandings();
        this.#draw();
    };

    #draw(): void {
        const ctx = this.#ctx;
        const data = this.#imageData?.data;
        const buffer = this.#buffer;
        if (!ctx || !data || !buffer || this.#w <= 0) return;

        const w = this.#w;
        const h = PILE_HEIGHT;
        const len = w * h * 4;

        for (let i = 0; i < len; i += 4) {
            data[i] = 0;
            data[i + 1] = 0;
            data[i + 2] = 0;
            data[i + 3] = 0;
        }

        for (let i = 0; i < buffer.length; i++) {
            if (buffer[i] !== 1) continue;
            const p = i * 4;
            data[p] = SNOW_R;
            data[p + 1] = SNOW_G;
            data[p + 2] = SNOW_B;
            data[p + 3] = 220;
        }

        const img = this.#imageData;
        if (img && this.#ctx) this.#ctx.putImageData(img, 0, 0);
    }
}
